#include <iostream>\n#include <string>\n#include <vector>\n\nint main() {\n  std::string word;\n  std::cin >> word;\n\n  std::vector<size_t> pr(word.length(), 0);\n\n  for (size_t i = 1; i < word.length(); i++) {\n    size_t count = pr[i - 1];\n    while ((word[i] != word[count]) && (count > 0)) {\n      count = pr[count - 1];\n    }\n    pr[i] = count;\n    if (word[i] == word[count]) {\n      pr[i]++;\n    }\n  }\n  for (size_t i : pr) {\n    std::cout << i << ' ';\n  }\n  return 0;\n}